        val outputAbi =
            listOf(
                InputOutput(
                    name = "levels", // unnamed output
                    type = "tuple[]",
                    indexed = false,
                    components =
                        listOf(
                            InputOutput(
                                name = "name",
                                type = "string",
                                indexed = false,
                                components = null,
                            ),
                            InputOutput(
                                name = "isX",
                                type = "bool",
                                indexed = false,
                                components = null,
                            ),
                            InputOutput(
                                name = "id",
                                type = "uint8",
                                indexed = false,
                                components = null,
