                    "maturityBlocks" to BigInteger("388800"),
                    "scaledRewardFactor" to BigInteger("250"),
                    "vetAmountRequiredToStake" to BigInteger("5000000000000000000000000"),
                ),
                mapOf(
                    "name" to "Mjolnir",
                    "isX" to false,
                    "id" to BigInteger("3"),
                    "maturityBlocks" to BigInteger("518400"),
                    "scaledRewardFactor" to BigInteger("350"),
