                ),
                mapOf(
                    "name" to "StrengthX",
                    "isX" to true,
                    "id" to BigInteger("5"),
                    "maturityBlocks" to BigInteger("0"),
                    "scaledRewardFactor" to BigInteger("300"),
                    "vetAmountRequiredToStake" to BigInteger("1600000000000000000000000"),
                ),
                mapOf(
                    "name" to "ThunderX",
                    "isX" to true,
                    "id" to BigInteger("6"),
                    "maturityBlocks" to BigInteger("0"),
                    "scaledRewardFactor" to BigInteger("400"),
                    "vetAmountRequiredToStake" to BigInteger("5600000000000000000000000"),
                ),
                mapOf(
                    "name" to "MjolnirX",
                    "isX" to true,
                    "id" to BigInteger("7"),
                    "maturityBlocks" to BigInteger("0"),
                    "scaledRewardFactor" to BigInteger("500"),
                    "vetAmountRequiredToStake" to BigInteger("15600000000000000000000000"),
                ),
                mapOf(
                    "name" to "Dawn",
                    "isX" to false,
                    "id" to BigInteger("8"),
                    "maturityBlocks" to BigInteger("17280"),
                    "scaledRewardFactor" to BigInteger("100"),
                    "vetAmountRequiredToStake" to BigInteger("10000000000000000000000"),
                ),
                mapOf(
                    "name" to "Lightning",
