                    "vetAmountRequiredToStake" to BigInteger("50000000000000000000000"),
                ),
                mapOf(
                    "name" to "Flash",
                    "isX" to false,
                    "id" to BigInteger("10"),
                    "maturityBlocks" to BigInteger("129600"),
                    "scaledRewardFactor" to BigInteger("130"),
                    "vetAmountRequiredToStake" to BigInteger("200000000000000000000000"),
                ),
